mapper.update:
UPDATE rank_week_user rw
JOIN (
    SELECT id, ROW_NUMBER() OVER (ORDER BY week_points DESC) AS rn
    FROM rank_week_user
    WHERE week_id = #{weekId}
) ranked ON rw.id = ranked.id
SET rw.rank_num = ranked.rn
WHERE rw.week_id = #{weekId}

mapper.select:
SELECT * FROM rank_week_user
WHERE week_id = #{weekId}
ORDER BY week_points DESC
LIMIT #{topN}
